package com.chaobo.scm.supplier.application.rfq;
import com.chaobo.scm.common.error.*;import com.chaobo.scm.supplier.application.integration.InboundEventPayloadStore;import com.chaobo.scm.supplier.application.masterdata.MasterDataEventConsumeLogPort;import com.chaobo.scm.supplier.domain.shared.IdentifierGenerator;import com.chaobo.scm.supplier.infrastructure.persistence.rfq.SupplierQuoteTodoMapper;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import tools.jackson.databind.ObjectMapper;
@Service public class RfqEventConsumerApplicationService{private static final String CONSUMER="supplier-rfq-todo";private final MasterDataEventConsumeLogPort inbox;private final SupplierQuoteTodoMapper todos;private final IdentifierGenerator ids;private final ObjectMapper json;private final InboundEventPayloadStore payloads;public RfqEventConsumerApplicationService(MasterDataEventConsumeLogPort inbox,SupplierQuoteTodoMapper todos,IdentifierGenerator ids,ObjectMapper json,InboundEventPayloadStore payloads){this.inbox=inbox;this.todos=todos;this.ids=ids;this.json=json;this.payloads=payloads;}@Transactional public void consume(RfqEvent event){if(!"PURCHASE".equals(event.sourceSystem()))throw new BusinessException(ErrorCode.BUSINESS_RULE_FAILED,"询价事件来源必须为PURCHASE");var claim=inbox.claim(event.sourceSystem(),event.eventCode(),event.eventType(),CONSUMER,event.sourceSystem()+":"+event.eventCode());if(claim==MasterDataEventConsumeLogPort.ClaimResult.ALREADY_SUCCEEDED)return;if(claim==MasterDataEventConsumeLogPort.ClaimResult.IN_PROGRESS)throw new BusinessException(ErrorCode.IDEMPOTENCY_CONFLICT,"询价事件正在处理");payloads.save(event.sourceSystem(),event.eventCode(),CONSUMER,event);try{if("RfqPublished".equals(event.eventType()))todos.upsert(ids.nextId(),event.rfqId(),event.rfqNo(),event.supplierId(),event.quoteDeadline(),json.writeValueAsString(event.payload()));else if("RfqBiddingClosed".equals(event.eventType()))todos.close(event.rfqId());else{inbox.markSucceeded(event.sourceSystem(),event.eventCode(),CONSUMER,true);return;}inbox.markSucceeded(event.sourceSystem(),event.eventCode(),CONSUMER,false);}catch(RuntimeException exception){inbox.recordFailure(event.sourceSystem(),event.eventCode(),event.eventType(),CONSUMER,event.sourceSystem()+":"+event.eventCode(),exception.getMessage());throw exception;}}}
